BEGIN TRANSACTION;
CREATE TABLE admissions (
	id INTEGER NOT NULL, 
	patient_id INTEGER NOT NULL, 
	ward_id INTEGER NOT NULL, 
	admitted_by INTEGER NOT NULL, 
	timestamp DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(admitted_by) REFERENCES users (id), 
	FOREIGN KEY(patient_id) REFERENCES patients (id), 
	FOREIGN KEY(ward_id) REFERENCES wards (id)
);
CREATE TABLE alembic_version (
	version_num VARCHAR(32) NOT NULL, 
	CONSTRAINT alembic_version_pkc PRIMARY KEY (version_num)
);
CREATE TABLE consultants (
	id INTEGER NOT NULL, 
	name VARCHAR(100) NOT NULL, 
	PRIMARY KEY (id), 
	UNIQUE (name)
);
CREATE TABLE discharges (
	id INTEGER NOT NULL, 
	patient_id INTEGER NOT NULL, 
	ward_id INTEGER NOT NULL, 
	discharged_by INTEGER NOT NULL, 
	timestamp DATETIME, 
	notes TEXT, discharge_type VARCHAR(20) DEFAULT 'Discharged', 
	PRIMARY KEY (id), 
	FOREIGN KEY(discharged_by) REFERENCES users (id), 
	FOREIGN KEY(patient_id) REFERENCES patients (id), 
	FOREIGN KEY(ward_id) REFERENCES wards (id)
);
CREATE TABLE marital_statuses (
	id INTEGER NOT NULL, 
	name VARCHAR(50) NOT NULL, 
	PRIMARY KEY (id), 
	UNIQUE (name)
);
CREATE TABLE occupations (
	id INTEGER NOT NULL, 
	name VARCHAR(100) NOT NULL, 
	PRIMARY KEY (id), 
	UNIQUE (name)
);
CREATE TABLE "patients" (
	id INTEGER NOT NULL, 
	age INTEGER NOT NULL, 
	status VARCHAR(50), 
	ward_id INTEGER, 
	is_deleted BOOLEAN, 
	hospital_id VARCHAR(6) NOT NULL, 
	surname VARCHAR(100) NOT NULL, 
	first_names VARCHAR(100) NOT NULL, 
	date_of_birth DATE NOT NULL, 
	sex VARCHAR(20) NOT NULL, 
	race VARCHAR(50) NOT NULL, 
	marital_status VARCHAR(50) NOT NULL, 
	occupation VARCHAR(100) NOT NULL, 
	religion VARCHAR(50), 
	residential_address TEXT NOT NULL, 
	contact_number VARCHAR(20) NOT NULL, 
	employer_name VARCHAR(100), 
	employer_address TEXT, 
	next_of_kin_name VARCHAR(100) NOT NULL, 
	next_of_kin_address TEXT NOT NULL, 
	next_of_kin_relationship VARCHAR(50) NOT NULL, 
	chief VARCHAR(100), 
	village VARCHAR(100), 
	tribe VARCHAR(100), 
	admission_datetime DATETIME NOT NULL, 
	referring_doctor_hospital VARCHAR(150) NOT NULL, 
	diagnosis TEXT NOT NULL, 
	doctor_name VARCHAR(100) NOT NULL, 
	consultant_name VARCHAR(100) NOT NULL, 
	pharmacy_name VARCHAR(100) NOT NULL, 
	discharge_datetime DATETIME, 
	created_at DATETIME, 
	updated_at DATETIME, next_of_kin_contact_number VARCHAR(20) NOT NULL DEFAULT 'Not Provided', treatment TEXT DEFAULT 'Not Provided', 
	PRIMARY KEY (id), 
	CONSTRAINT uq_patient_hospital_id UNIQUE (hospital_id), 
	FOREIGN KEY(ward_id) REFERENCES wards (id)
);
