CREATE TABLE pharmacies (
	id INTEGER NOT NULL, 
	name VARCHAR(100) NOT NULL, 
	PRIMARY KEY (id), 
	UNIQUE (name)
);
CREATE TABLE races (
	id INTEGER NOT NULL, 
	name VARCHAR(50) NOT NULL, 
	PRIMARY KEY (id), 
	UNIQUE (name)
);
016616');
CREATE TABLE referring_doctors_hospitals (
	id INTEGER NOT NULL, 
	name VARCHAR(150) NOT NULL, 
	type VARCHAR(50) NOT NULL, 
	PRIMARY KEY (id), 
	UNIQUE (name)
);
CREATE TABLE roles (
	id INTEGER NOT NULL, 
	name VARCHAR(50) NOT NULL, 
	PRIMARY KEY (id), 
	UNIQUE (name)
);
CREATE TABLE transfers (
	id INTEGER NOT NULL, 
	patient_id INTEGER NOT NULL, 
	from_ward_id INTEGER NOT NULL, 
	to_ward_id INTEGER NOT NULL, 
	transferred_by INTEGER NOT NULL, 
	timestamp DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(from_ward_id) REFERENCES wards (id), 
	FOREIGN KEY(patient_id) REFERENCES patients (id), 
	FOREIGN KEY(to_ward_id) REFERENCES wards (id), 
	FOREIGN KEY(transferred_by) REFERENCES users (id)
);
CREATE TABLE users (
	id INTEGER NOT NULL, 
	name VARCHAR(100) NOT NULL, 
	email VARCHAR(120) NOT NULL, 
	password_hash VARCHAR(128) NOT NULL, 
	role_id INTEGER NOT NULL, 
	ward_id INTEGER, 
	PRIMARY KEY (id), 
	FOREIGN KEY(role_id) REFERENCES roles (id), 
	FOREIGN KEY(ward_id) REFERENCES wards (id), 
	UNIQUE (email)
);
CREATE TABLE wards (
	id INTEGER NOT NULL, 
	name VARCHAR(100) NOT NULL, 
	type VARCHAR(50) NOT NULL, 
	capacity INTEGER, 
	PRIMARY KEY (id), 
	UNIQUE (name)
);
COMMIT;
